'use client';

import React, { useCallback, useMemo, useState } from "react";

type ReportStatus = "NEW" | "IN_PROGRESS" | "RESOLVED" | "REJECTED";

interface Report {
  id: string;
  title: string;
  description: string;
  status: ReportStatus;
  createdAt: string;
  city?: string;
  author?: string;
}

const createdAtFormatter = new Intl.DateTimeFormat("ro-RO", {
  dateStyle: "medium",
  timeStyle: "short"
});

const statusOrder: ReportStatus[] = ["NEW", "IN_PROGRESS", "RESOLVED", "REJECTED"];

export function formatStatus(status: ReportStatus) {
  switch (status) {
    case "NEW":
      return "Nouă";
    case "IN_PROGRESS":
      return "În lucru";
    case "RESOLVED":
      return "Rezolvată";
    case "REJECTED":
      return "Respinsă";
    default:
      return status;
  }
}

const statusStyles: Record<ReportStatus, { badge: string; dot: string; hint: string }> = {
  NEW: { badge: "bg-gray-200 text-gray-800", dot: "bg-gray-400", hint: "Nu apare pe harta publică" },
  IN_PROGRESS: { badge: "bg-amber-100 text-amber-800", dot: "bg-amber-500", hint: "Vizibil pe hartă" },
  RESOLVED: { badge: "bg-emerald-100 text-emerald-800", dot: "bg-emerald-500", hint: "Vizibil pe hartă" },
  REJECTED: { badge: "bg-rose-100 text-rose-800", dot: "bg-rose-500", hint: "Nu apare pe harta publică" }
};

const mockReports: Report[] = [
  {
    id: "rep-01",
    title: "Iluminat stradal defect",
    description: "Lampa de pe Str. Lalelelor 14 nu mai funcționează de 3 zile.",
    status: "NEW",
    createdAt: new Date().toISOString(),
    city: "Cluj-Napoca",
    author: "@andreea"
  },
  {
    id: "rep-02",
    title: "Gropi în carosabil",
    description: "Segmentele din apropiere de Piața Avram Iancu sunt greu de traversat.",
    status: "IN_PROGRESS",
    createdAt: new Date(Date.now() - 3600 * 1000 * 24).toISOString(),
    city: "Arad",
    author: "@mihai"
  },
  {
    id: "rep-03",
    title: "Deșeuri abandonate",
    description: "Malul Someșului a fost din nou încărcat cu saci menajeri.",
    status: "RESOLVED",
    createdAt: new Date(Date.now() - 3600 * 1000 * 48).toISOString(),
    city: "Satu Mare",
    author: "@ioana"
  }
];

async function patchReportStatus(reportId: string, status: ReportStatus) {
  await new Promise((resolve) => setTimeout(resolve, 600));
  console.info(`PATCH /api/reports/${reportId}/status -> ${status}`);
  return status;
}

export function AdminDashboard() {
  const [reports, setReports] = useState<Report[]>(mockReports);
  const [pending, setPending] = useState<Record<string, ReportStatus | null>>({});
  const markerHint = useMemo(
    () => "Marcajul apare pe harta publică doar pentru rapoartele În lucru sau Rezolvate.",
    []
  );

  const handleStatusChange = useCallback(
    async (reportId: string, nextStatus: ReportStatus) => {
      setPending((prev: Record<string, ReportStatus | null>) => ({ ...prev, [reportId]: nextStatus }));
      setReports((prev: Report[]) =>
        prev.map((report: Report) =>
          report.id === reportId ? { ...report, status: nextStatus } : report
        )
      );

      try {
        await patchReportStatus(reportId, nextStatus);
      } catch (error) {
        console.error("Nu am putut actualiza statusul", error);
        setReports(mockReports);
      } finally {
        setPending((prev: Record<string, ReportStatus | null>) => ({ ...prev, [reportId]: null }));
      }
    },
    []
  );

  return (
    <div className="w-full px-4 py-8 sm:px-6 lg:px-8">
      <div className="mx-auto flex w-full max-w-6xl flex-col gap-6">
        <header className="flex flex-col gap-2">
          <p className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-500">
            Admin / Triage Dashboard
          </p>
          <div className="flex flex-col gap-3 rounded-3xl bg-white/90 p-6 shadow-lg shadow-slate-100">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <h1 className="text-2xl font-semibold text-slate-900">Rapoarte comunitare</h1>
              <span className="text-sm font-medium text-slate-500">{markerHint}</span>
            </div>
            <div className="flex flex-wrap gap-3 text-xs text-slate-500">
              {statusOrder.map((status) => {
                const meta = statusStyles[status];
                return (
                  <div key={status} className="flex items-center gap-2 rounded-full bg-slate-100 px-3 py-1">
                    <span className={`h-2 w-2 rounded-full ${meta.dot}`} />
                    <span className="font-semibold text-slate-700">{formatStatus(status)}</span>
                    <span className="text-slate-400">{meta.hint}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </header>

        <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {reports.map((report) => {
            const meta = statusStyles[report.status];
            const isUpdating = Boolean(pending[report.id]);
            return (
              <article
                key={report.id}
                className="flex flex-col gap-4 rounded-3xl bg-white p-6 shadow-lg shadow-slate-100 transition hover:-translate-y-0.5 hover:shadow-xl"
              >
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <h2 className="text-base font-semibold text-slate-900">{report.title}</h2>
                    <p className="text-xs text-slate-400">
                      Creat {createdAtFormatter.format(new Date(report.createdAt))}
                    </p>
                  </div>
                  <span className={`flex items-center gap-2 rounded-full px-3 py-1 text-xs font-semibold ${meta.badge}`}>
                    <span className={`h-2 w-2 rounded-full ${meta.dot}`} />
                    {formatStatus(report.status)}
                  </span>
                </div>

                <p className="text-sm text-slate-600">{report.description}</p>

                <div className="flex flex-wrap gap-3 text-xs text-slate-500">
                  {report.city ? <span className="rounded-full bg-slate-100 px-3 py-1">{report.city}</span> : null}
                  {report.author ? <span className="rounded-full bg-slate-100 px-3 py-1">Autor: {report.author}</span> : null}
                  <span className="rounded-full bg-slate-50 px-3 py-1">{meta.hint}</span>
                </div>

                <label className="flex flex-col gap-2 text-sm font-medium text-slate-900">
                  Actualizează statusul
                  <select
                    className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-2 text-sm font-medium text-slate-900 focus:border-slate-400 focus:outline-none"
                    value={report.status}
                    onChange={(event) => handleStatusChange(report.id, event.target.value as ReportStatus)}
                    disabled={isUpdating}
                  >
                    {statusOrder.map((status) => (
                      <option key={status} value={status}>
                        {formatStatus(status)}
                      </option>
                    ))}
                  </select>
                </label>

                {isUpdating ? <p className="text-xs font-medium text-amber-700">Se sincronizează...</p> : null}
              </article>
            );
          })}
        </section>
      </div>
    </div>
  );
}
